// === CACHE MANAGEMENT (mantido) ===
interface CacheEntry<T> {
  data: T;
  timestamp: number;
  ttl: number;
}

class FluxCache {
  private cache = new Map<string, CacheEntry<any>>();
  
  set<T>(key: string, data: T, ttl: number = 5 * 60 * 1000): void {
    this.cache.set(key, {
      data,
      timestamp: Date.now(),
      ttl
    });
  }
  
  get<T>(key: string): T | null {
    const entry = this.cache.get(key);
    if (!entry) return null;
    
    if (Date.now() - entry.timestamp > entry.ttl) {
      this.cache.delete(key);
      return null;
    }
    
    return entry.data;
  }
  
  invalidate(pattern?: string): void {
    if (!pattern) {
      this.cache.clear();
      return;
    }
    
    const keys = Array.from(this.cache.keys());
    keys.forEach(key => {
      if (key.includes(pattern)) {
        this.cache.delete(key);
      }
    });
  }
  
  getStats(): { size: number; keys: string[] } {
    return {
      size: this.cache.size,
      keys: Array.from(this.cache.keys())
    };
  }
}

// === SINGLETON INSTANCES ===
const fluxCache = new FluxCache();

// === UTILITY FUNCTIONS CORRIGIDAS ===

// ✅ Helper para aplicar abortSignal condicionalmente
const withAbortSignal = <T>(query: any, signal?: AbortSignal): T => {
  if (signal && typeof query.abortSignal === 'function') {
    return query.abortSignal(signal);
  }
  return query;
};

// ✅ Retry utility com exponential backoff
const withRetry = async <T>(
  fn: () => Promise<T>,
  maxRetries: number = 3,
  delay: number = 1000
): Promise<T> => {
  let lastError: Error | null = null;
  
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error as Error;
      
      if (i === maxRetries) break;
      
      // Exponential backoff
      await new Promise(resolve => setTimeout(resolve, delay * Math.pow(2, i)));
    }
  }
  
  if (lastError) {
    throw lastError;
  } else {
    throw new Error('Unknown error occurred during retry');
  }
};

// ✅ CORREÇÃO CRÍTICA: Session validation com verificação de usuário
const getValidSession = async () => {
  try {
    // ✅ Primeiro verificar se há usuário autenticado
    const { data: { user }, error: userError } = await supabase.auth.getUser();
    
    if (userError) {
      console.error('❌ Erro ao verificar usuário:', userError);
      throw new Error(`User error: ${userError.message}`);
    }
    
    if (!user) {
      console.warn('⚠️ Usuário não autenticado');
      throw new Error('No authenticated user');
    }
    
    // ✅ Verificar se há sessão válida
    const { data: { session }, error: sessionError } = await supabase.auth.getSession();
    
    if (sessionError) {
      console.error('❌ Erro na sessão:', sessionError);
      throw new Error(`Session error: ${sessionError.message}`);
    }
    
    if (!session) {
      console.warn('⚠️ Nenhuma sessão ativa');
      throw new Error('No active session');
    }
    
    console.log('✅ Usuário e sessão válidos:', user.email);
    return { user, session };
  } catch (error) {
    console.error('❌ getValidSession failed:', error);
    throw error;
  }
};

// ✅ Helper para extrair dados do Supabase com type safety
const extractSupabaseData = <T>(
  result: unknown,
  defaultValue: T
): T => {
  if (result && typeof result === 'object' && 'data' in result) {
    const typedResult = result as { data?: T; error?: any };
    if (typedResult.error) {
      console.warn('⚠️ Supabase query error:', typedResult.error);
      return defaultValue;
    }
    return typedResult.data ?? defaultValue;
  }
  return defaultValue;
};

// ✅ Helper para Promise.allSettled results
const extractSettledData = <T>(
  result: PromiseSettledResult<any>,
  defaultValue: T
): T => {
  if (result.status === 'fulfilled') {
    return extractSupabaseData<T>(result.value, defaultValue);
  } else {
    console.warn('⚠️ Promise rejected:', result.reason);
    return defaultValue;
  }
};

// === STATE MANAGEMENT ===
interface FluxState {
  metrics: MetricsData | null;
  analyses: Analysis[];
  sites: Site[];
  userSettings: UserSettings | null;
  loading: boolean;
  error: string | null;
}

// === HOOK INTERFACE ===
interface FluxDataReturn {
  // Data
  metrics: MetricsData | null;
  analyses: Analysis[];
  sites: Site[];
  userSettings: UserSettings | null;
  // States
  loading: boolean;
  error: string | null;
  // Methods
  refreshData: () => Promise<void>;
  uploadAndAnalyze: (csvData: string, siteUrl: string) => Promise<any>;
  generateScript: (siteId: string) => Promise<string>;
  updateUserSettings: (settings: Partial<UserSettings>) => Promise<void>;
  addSite: (url: string) => Promise<void>;
  updateSite: (siteId: string, updates: Partial<Site>) => Promise<void>;
  // Cache management
  clearCache: () => void;
  getCacheStats: () => { size: number; keys: string[] };
}

// === MAIN HOOK ===
export function useFluxData(): FluxDataReturn {
  const { user } = useAuth();
  
  // ✅ Centralized state
  const [state, setState] = useState<FluxState>({
    metrics: null,
    analyses: [],
    sites: [],
    userSettings: null,
    loading: false,
    error: null
  });
  
  // ✅ Refs para controle
  const abortControllerRef = useRef<AbortController | null>(null);
  const refreshInProgressRef = useRef(false);
  const subscriptionsRef = useRef<any[]>([]);
  
  // ✅ Memoized user ID
  const userId = useMemo(() => user?.id, [user]);
  
  // ✅ State update helper
  const updateState = useCallback((updates: Partial<FluxState>) => {
    setState(prev => ({ ...prev, ...updates }));
  }, []);
  
  // ✅ Cache key generator
  const getCacheKey = useCallback((type: string, params?: any) => {
    const baseKey = `${userId}_${type}`;
    return params ? `${baseKey}_${JSON.stringify(params)}` : baseKey;
  }, [userId]);
  
  // ✅ Real-time subscriptions setup (mantido)
  const setupSubscriptions = useCallback(async () => {
    if (!userId) return;
    
    // Cleanup existing subscriptions
    subscriptionsRef.current.forEach(sub => sub?.unsubscribe());
    subscriptionsRef.current = [];
    
    try {
      console.log('🔄 Setting up real-time subscriptions...');
      
      // Metrics updates
      const metricsChannel = supabase
        .channel(`flux_metrics_${userId}`)
        .on('postgres_changes', 
          { 
            event: '*', 
            schema: 'public', 
            table: 'metrics',
            filter: `client_id=eq.${userId}`
          },
          (payload) => {
            console.log('📊 Real-time metrics update:', payload);
            fluxCache.invalidate('metrics');
            if (payload.eventType === 'UPDATE' || payload.eventType === 'INSERT') {
              updateState({ metrics: payload.new as MetricsData });
            }
          }
        )
        .subscribe();
      
      // Analyses updates
      const analysesChannel = supabase
        .channel(`flux_analyses_${userId}`)
        .on('postgres_changes',
          { 
            event: '*', 
            schema: 'public', 
            table: 'adsense_analyses',
            filter: `client_id=eq.${userId}`
          },
          (payload) => {
            console.log('📈 Real-time analysis update:', payload);
            fluxCache.invalidate('analyses');
            
            if (payload.eventType === 'INSERT') {
              setState(prev => ({
                ...prev,
                analyses: [payload.new as Analysis, ...prev.analyses]
              }));
            }
          }
        )
        .subscribe();
      
      // Sites updates
      const sitesChannel = supabase
        .channel(`flux_sites_${userId}`)
        .on('postgres_changes',
          { 
            event: '*', 
            schema: 'public', 
            table: 'sites',
            filter: `client_id=eq.${userId}`
          },
          (payload) => {
            console.log('🌐 Real-time site update:', payload);
            fluxCache.invalidate('sites');
            refreshData();
          }
        )
        .subscribe();
      
      subscriptionsRef.current = [metricsChannel, analysesChannel, sitesChannel];
      console.log('✅ Real-time subscriptions setup completed');
      
    } catch (error) {
      console.error('❌ Error setting up subscriptions:', error);
    }
  }, [userId, updateState]);
  
  // ✅ CORREÇÃO CRÍTICA: Enhanced data fetching com autenticação correta
  const fetchUserData = useCallback(async (signal?: AbortSignal) => {
    if (!userId) return;
    
    try {
      // ✅ CRÍTICO: Verificar autenticação PRIMEIRO
      const { user: authUser, session } = await getValidSession();
      
      // Check cache first
      const cacheKey = getCacheKey('user_data');
      const cachedData = fluxCache.get<Partial<FluxState>>(cacheKey);
      
      if (cachedData) {
        console.log('📦 Using cached user data');
        updateState(cachedData);
        return;
      }
      
      console.log('🔄 Fetching fresh user data for user:', authUser.email);
      
      // ✅ CORREÇÃO: Parallel fetch com usuário autenticado
      const [sitesResult, analysesResult, settingsResult] = await Promise.allSettled([
        withAbortSignal(
          supabase
            .from('sites')
            .select('*')
            .eq('client_id', authUser.id) // ✅ Usar authUser.id
            .order('created_at', { ascending: false }),
          signal
        ),
        
        withAbortSignal(
          supabase
            .from('adsense_analyses')
            .select('*')
            .eq('client_id', authUser.id) // ✅ Usar authUser.id
            .order('created_at', { ascending: false })
            .limit(50),
          signal
        ),
        
        withAbortSignal(
          supabase
            .from('user_settings')
            .select('*')
            .eq('client_id', authUser.id) // ✅ Usar authUser.id
            .maybeSingle(), // ✅ CORREÇÃO CRÍTICA: .single() → .maybeSingle()
          signal
        )
      ]);
      
      // ✅ Process results with helper functions
      const sites = extractSettledData<Site[]>(sitesResult, []);
      const analyses = extractSettledData<Analysis[]>(analysesResult, []);
      const userSettings = extractSettledData<UserSettings | null>(settingsResult, null);
      
      // ✅ Fetch latest metrics if sites exist - CORRIGIDO
      let metrics: MetricsData | null = null;
      if (sites.length > 0) {
        try {
          const metricsQuery = await withAbortSignal(
            supabase
              .from('metrics')
              .select('*')
              .in('site_id', sites.map((site: Site) => site.id))
              .order('timestamp', { ascending: false })
              .limit(1),
            signal
          );
          
          // ✅ CORREÇÃO: Usar helper function para extrair dados
          const metricsData = extractSupabaseData<MetricsData[]>(metricsQuery, []);
          metrics = metricsData[0] || null;
          
        } catch (metricsError) {
          console.warn('⚠️ Could not fetch metrics:', metricsError);
        }
      }
      
      // ✅ Handle missing user settings with defaults
      const finalUserSettings: UserSettings = userSettings || {
        id: crypto.randomUUID(),
        client_id: authUser.id, // ✅ Usar authUser.id
        notifications_enabled: true,
        auto_optimization: false,
        report_frequency: 'weekly',
        email_notifications: true,
        sms_notifications: false,
        webhook_notifications: false,
        theme: 'light',
        timezone: 'America/Sao_Paulo',
        language: 'pt-BR'
      };
      
      const newState: Partial<FluxState> = {
        sites,
        analyses,
        userSettings: finalUserSettings,
        metrics,
        error: null
      };
      
      // Update state and cache
      updateState(newState);
      fluxCache.set(cacheKey, newState, 3 * 60 * 1000); // 3 minutes TTL
      
      console.log('✅ User data fetched successfully:', {
        sites: sites.length,
        analyses: analyses.length,
        metrics: !!metrics,
        userSettings: !!finalUserSettings
      });
      
    } catch (error: any) {
      if (error.name === 'AbortError') {
        console.log('🔄 Data fetch aborted');
        return;
      }
      
      console.error('❌ Error fetching user data:', error);
      updateState({ error: error.message });
    }
  }, [userId, updateState, getCacheKey]);
  
  // ✅ Main refresh function with concurrency control (mantido)
  const refreshData = useCallback(async (): Promise<void> => {
    if (!userId) return;
    
    // Prevent concurrent executions
    if (refreshInProgressRef.current) {
      console.log('🔄 Refresh already in progress, skipping...');
      return;
    }
    
    refreshInProgressRef.current = true;
    updateState({ loading: true, error: null });
    
    // Abort any previous request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    
    abortControllerRef.current = new AbortController();
    
    try {
      await withRetry(
        () => fetchUserData(abortControllerRef.current?.signal),
        3,
        1000
      );
    } catch (error: any) {
      console.error('❌ RefreshData failed after retries:', error);
      updateState({ error: error.message });
    } finally {
      updateState({ loading: false });
      refreshInProgressRef.current = false;
    }
  }, [userId, fetchUserData, updateState]);
  
  // ✅ CORREÇÃO: Enhanced upload and analyze com autenticação
  const uploadAndAnalyze = useCallback(async (csvData: string, siteUrl: string) => {
    if (!userId) throw new Error('User not authenticated');
    
    try {
      const { user: authUser, session } = await getValidSession(); // ✅ Verificar auth
      
      console.log('🔄 Uploading CSV data for analysis:', {
        siteUrl,
        dataLength: csvData.length,
        userId: authUser.id
      });
      
      const { data, error } = await supabase.functions.invoke('analyze-adsense', {
        body: {
          csv_data: csvData,
          site_url: siteUrl,
          user_id: authUser.id, // ✅ Usar authUser.id
          timestamp: new Date().toISOString()
        }
      });
      
      if (error) throw error;
      
      console.log('✅ Analysis completed successfully:', data);
      
      // Invalidate relevant caches
      fluxCache.invalidate('analyses');
      fluxCache.invalidate('user_data');
      
      // Refresh data to get latest analysis
      await refreshData();
      
      return data;
    } catch (error: any) {
      console.error('❌ Upload and analyze error:', error);
      throw new Error(error.message || 'Error processing CSV analysis');
    }
  }, [userId, refreshData]);
  
  // ✅ CORREÇÃO: Enhanced script generation com autenticação
  const generateScript = useCallback(async (siteId: string): Promise<string> => {
    if (!userId) throw new Error('User not authenticated');
    
    try {
      const { user: authUser, session } = await getValidSession(); // ✅ Verificar auth
      
      // Check cache first
      const cacheKey = getCacheKey('script', siteId);
      const cachedScript = fluxCache.get<string>(cacheKey);
      
      if (cachedScript) {
        console.log('📦 Using cached optimization script for site:', siteId);
        return cachedScript;
      }
      
      console.log('🔄 Generating new optimization script for site:', siteId);
      
      const { data, error } = await supabase.functions.invoke('flux-optimizer-engine', {
        body: {
          site_id: siteId,
          user_id: authUser.id, // ✅ Usar authUser.id
          action: 'generate_script',
          timestamp: new Date().toISOString()
        }
      });
      
      if (error) throw error;
      
      const script = data.script || '';
      
      // Cache script for 1 hour
      fluxCache.set(cacheKey, script, 60 * 60 * 1000);
      
      console.log('✅ Optimization script generated successfully');
      
      return script;
    } catch (error: any) {
      console.error('❌ Script generation error:', error);
      throw new Error(error.message || 'Error generating optimization script');
    }
  }, [userId, getCacheKey]);
  
  // ✅ CORREÇÃO: Enhanced user settings update com autenticação
  const updateUserSettings = useCallback(async (settings: Partial<UserSettings>) => {
    if (!userId) throw new Error('User not authenticated');
    
    try {
      const { user: authUser, session } = await getValidSession(); // ✅ Verificar auth
      
      const { data, error } = await supabase
        .from('user_settings')
        .upsert({
          client_id: authUser.id, // ✅ Usar authUser.id
          ...settings,
          updated_at: new Date().toISOString()
        }, {
          onConflict: 'client_id'
        })
        .select()
        .maybeSingle(); // ✅ CORREÇÃO: .single() → .maybeSingle()
      
      if (error) throw error;
      
      updateState({ userSettings: data });
      fluxCache.invalidate('user_data');
      
      console.log('✅ User settings updated successfully');
      
    } catch (error: any) {
      console.error('❌ Update user settings error:', error);
      throw new Error(error.message || 'Error updating user settings');
    }
  }, [userId, updateState]);
  
  // ✅ CORREÇÃO: Enhanced add site com autenticação
  const addSite = useCallback(async (url: string) => {
    if (!userId) throw new Error('User not authenticated');
    
    try {
      const { user: authUser, session } = await getValidSession(); // ✅ Verificar auth
      
      console.log('🔄 Adding new site:', url);
      
      const { data, error } = await supabase.functions.invoke('create-site', {
        body: {
          url,
          user_id: authUser.id, // ✅ Usar authUser.id
          timestamp: new Date().toISOString()
        }
      });
      
      if (error) throw error;
      
      // Invalidate caches
      fluxCache.invalidate('sites');
      fluxCache.invalidate('user_data');
      
      // Refresh data
      await refreshData();
      
      console.log('✅ Site added successfully:', data);
      
    } catch (error: any) {
      console.error('❌ Add site error:', error);
      throw new Error(error.message || 'Error adding site');
    }
  }, [userId, refreshData]);
  
  // ✅ CORREÇÃO: Enhanced update site com autenticação
  const updateSite = useCallback(async (siteId: string, updates: Partial<Site>) => {
    if (!userId) throw new Error('User not authenticated');
    
    try {
      const { user: authUser, session } = await getValidSession(); // ✅ Verificar auth
      
      const { error } = await supabase
        .from('sites')
        .update({
          ...updates,
          updated_at: new Date().toISOString()
        })
        .eq('id', siteId)
        .eq('client_id', authUser.id); // ✅ Usar authUser.id
      
      if (error) throw error;
      
      // Invalidate caches
      fluxCache.invalidate('sites');
      fluxCache.invalidate('user_data');
      
      // Refresh data
      await refreshData();
      
      console.log('✅ Site updated successfully');
      
    } catch (error: any) {
      console.error('❌ Update site error:', error);
      throw new Error(error.message || 'Error updating site');
    }
  }, [userId, refreshData]);
  
  // ✅ Cache management (mantidos)
  const clearCache = useCallback(() => {
    fluxCache.invalidate();
    console.log('🗑️ All cache cleared');
  }, []);
  
  const getCacheStats = useCallback(() => {
    return fluxCache.getStats();
  }, []);
  
  // ✅ Setup effect (mantido)
  useEffect(() => {
    if (userId) {
      console.log('👤 User authenticated, initializing Flux Data...');
      
      refreshInProgressRef.current = false;
      setupSubscriptions();
      
      const initTimer = setTimeout(() => {
        refreshData();
      }, 500);
      
      return () => {
        clearTimeout(initTimer);
        subscriptionsRef.current.forEach(sub => sub?.unsubscribe());
        subscriptionsRef.current = [];
        
        if (abortControllerRef.current) {
          abortControllerRef.current.abort();
        }
      };
    }
  }, [userId, setupSubscriptions, refreshData]);
  
  // ✅ Cleanup effect (mantido)
  useEffect(() => {
    return () => {
      console.log('🧹 Cleaning up Flux Data hook...');
      subscriptionsRef.current.forEach(sub => sub?.unsubscribe());
      
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);
  
  return {
    ...state,
    refreshData,
    uploadAndAnalyze,
    generateScript,
    updateUserSettings,
    addSite,
    updateSite,
    clearCache,
    getCacheStats
  };
}

// === SPECIALIZED HOOKS CORRIGIDOS ===

// ✅ Trial status hook com autenticação correta
export function useTrialStatus() {
  const { user } = useAuth();
  const [data, setData] = useState<TrialStatusData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const fetchStatus = useCallback(async () => {
    if (!user?.id) return;
    
    setLoading(true);
    setError(null);
    
    try {
      const { user: authUser, session } = await getValidSession(); // ✅ Verificar auth
      
      const { data: responseData, error: responseError } = await supabase.functions.invoke('check-trial-status', {
        body: {
          client_id: authUser.id, // ✅ Usar authUser.id
          action: 'get_trial_status'
        }
      });
      
      if (responseError) throw responseError;
      
      setData(responseData as TrialStatusData);
      console.log('✅ Trial status loaded:', responseData);
      
    } catch (err: any) {
      setError(err.message);
      console.error('❌ Error fetching trial status:', err);
    } finally {
      setLoading(false);
    }
  }, [user?.id]);
  
  useEffect(() => {
    if (user?.id) {
      const timer = setTimeout(fetchStatus, 300);
      return () => clearTimeout(timer);
    }
  }, [user?.id, fetchStatus]);
  
  return { data, loading, error };
}

// ✅ Site-specific metrics hook (mantido - já estava correto)
export function useMetrics(siteId: string) {
  const { user } = useAuth();
  const [data, setData] = useState<MetricsData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const fetchMetrics = useCallback(async () => {
    if (!user?.id || !siteId) return;
    
    setLoading(true);
    setError(null);
    
    try {
      const { data: metricsData, error: metricsError } = await supabase
        .from('metrics')
        .select('*')
        .eq('site_id', siteId)
        .order('timestamp', { ascending: false })
        .limit(1);
      
      if (metricsError) throw metricsError;
      
      setData(metricsData?.[0] as MetricsData || null);
      console.log('✅ Metrics loaded for site:', siteId);
      
    } catch (err: any) {
      setError(err.message);
      console.error('❌ Error fetching metrics:', err);
    } finally {
      setLoading(false);
    }
  }, [user?.id, siteId]);
  
  useEffect(() => {
    if (user?.id && siteId) {
      const timer = setTimeout(fetchMetrics, 200);
      return () => clearTimeout(timer);
    }
  }, [user?.id, siteId, fetchMetrics]);
  
  return { data, loading, error };
}

// ✅ AdSense analysis hook (mantido - já estava correto)
export function useAnalyzeAdSense() {
  const { uploadAndAnalyze } = useFluxData();
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const analyzeCSV = useCallback(async (csvData: string, siteUrl: string) => {
    setLoading(true);
    setError(null);
    
    try {
      const result = await uploadAndAnalyze(csvData, siteUrl);
      setData(result);
      return result;
    } catch (err: any) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, [uploadAndAnalyze]);
  
  return {
    data,
    loading,
    error,
    analyzeCSV,
    analyze: uploadAndAnalyze
  };
}

export default useFluxData;
