// src/contexts/AuthContext.tsx - ORIGINAL com logging enterprise

import React, { createContext, useContext, useEffect, useState, useRef } from 'react';
import { User, Session, AuthChangeEvent } from '@supabase/supabase-js';

interface AuthContextType {
  isAuthenticated: boolean;
  loading: boolean;
  isReady: boolean;
  user: User | null;
  userPlan: string;
  session: Session | null;
  canPerformAction?: (action: string) => boolean;
  login: (email: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [isReady, setIsReady] = useState(false);
  const [userPlan, setUserPlan] = useState<string>('free');
  
  // ✅ ORIGINAL: Refs para controlar estado
  const isMountedRef = useRef(true);
  const lastSessionTokenRef = useRef<string | null>(null);
  const authSubscriptionRef = useRef<any>(null);

  // ✅ ORIGINAL: Single Supabase client getter
  const getSupabaseClient = async () => {
    if ((window as any).supabase?.auth) {
      return (window as any).supabase;
    }
    
    let attempts = 0;
    while (attempts < 20) {
      await new Promise(resolve => setTimeout(resolve, 100));
      if ((window as any).supabase?.auth) {
        return (window as any).supabase;
      }
      attempts++;
    }
    throw new Error('Supabase client não encontrado');
  };

  // ✅ ENTERPRISE: Enhanced user plan fetching
  useEffect(() => {
    const fetchUserPlan = async () => {
      if (!user?.id) {
        setUserPlan('free');
        return;
      }

      try {
        console.log('📊 AuthContext: Buscando plano do usuário...');
        const supabaseClient = await getSupabaseClient();
        
        const { data, error } = await supabaseClient
          .from('clients')
          .select('plan, subscription_status, trial_end')
          .eq('id', user.id)
          .maybeSingle(); // ✅ ENTERPRISE: maybeSingle para evitar erros

        if (!error && data) {
          const plan = data.plan || 'free';
          console.log(`✅ AuthContext: Plano do usuário: ${plan}`);
          setUserPlan(plan);
        } else {
          console.warn('⚠️ AuthContext: Usando plano padrão:', error?.message);
          setUserPlan('free');
        }
      } catch (error) {
        console.error('❌ AuthContext: Erro ao buscar plano do usuário:', error);
        setUserPlan('free');
      }
    };

    fetchUserPlan();
  }, [user?.id]);

  // ✅ ORIGINAL: Inicialização (sem modificações cross-domain)
  useEffect(() => {
    let initializationTimeout: NodeJS.Timeout;
    
    const initializeAuth = async () => {
      try {
        console.log('🔍 AuthContext: Inicializando autenticação...');
        
        const supabaseClient = await getSupabaseClient();
        
        if (!isMountedRef.current) return;

        // ✅ ORIGINAL: Obter sessão inicial
        const { data: { session }, error } = await supabaseClient.auth.getSession();
        
        if (error) {
          console.error('❌ AuthContext: Erro ao buscar sessão:', error);
        }

        if (!isMountedRef.current) return;

        console.log('📊 AuthContext: Sessão inicial:', {
          hasSession: !!session,
          userId: session?.user?.id,
          email: session?.user?.email
        });

        // ✅ ORIGINAL: Definir estado inicial
        setSession(session);
        setUser(session?.user ?? null);
        setIsReady(true);
        setLoading(false);
        
        if (session?.access_token) {
          lastSessionTokenRef.current = session.access_token;
        }

        // ✅ ORIGINAL: Auth state change listener
        let lastEventTime = 0;
        let lastEventType = '';
        
        const { data: { subscription } } = supabaseClient.auth.onAuthStateChange(
          (event: AuthChangeEvent, newSession: Session | null) => {
            const now = Date.now();
            const eventKey = `${event}-${newSession?.access_token?.slice(-8) || 'null'}`;
            
            // ✅ ORIGINAL: Throttle
            if (eventKey === lastEventType && (now - lastEventTime) < 1000) {
              console.log('🔄 AuthContext: Auth event throttled:', event);
              return;
            }
            
            lastEventTime = now;
            lastEventType = eventKey;
            
            console.log('🔐 AuthContext: Auth state change:', event, {
              hasSession: !!newSession,
              userId: newSession?.user?.id,
              tokenChanged: newSession?.access_token !== lastSessionTokenRef.current
            });

            if (!isMountedRef.current) return;

            // ✅ ORIGINAL: Só atualizar se token mudou
            const tokenChanged = newSession?.access_token !== lastSessionTokenRef.current;
            
            if (tokenChanged || event === 'SIGNED_OUT') {
              setSession(newSession);
              setUser(newSession?.user ?? null);
              
              if (event === 'SIGNED_OUT') {
                setUserPlan('free');
              }
              
              if (newSession?.access_token) {
                lastSessionTokenRef.current = newSession.access_token;
              } else {
                lastSessionTokenRef.current = null;
              }
            }
            
            if (!isReady) {
              setIsReady(true);
            }
            
            setLoading(false);
          }
        );

        authSubscriptionRef.current = subscription;
        
      } catch (error) {
        console.error('❌ AuthContext: Erro crítico na inicialização:', error);
        
        if (isMountedRef.current) {
          setSession(null);
          setUser(null);
          setUserPlan('free');
          setIsReady(true);
          setLoading(false);
        }
      }
    };

    // ✅ ENTERPRISE: Timeout de segurança
    initializationTimeout = setTimeout(() => {
      if (!isReady && isMountedRef.current) {
        console.warn('⚠️ AuthContext: Timeout de inicialização, marcando como ready');
        setIsReady(true);
        setLoading(false);
      }
    }, 8000);

    initializeAuth();

    return () => {
      isMountedRef.current = false;
      clearTimeout(initializationTimeout);
      
      if (authSubscriptionRef.current) {
        authSubscriptionRef.current.unsubscribe();
        authSubscriptionRef.current = null;
      }
    };
  }, []);

  // ✅ ORIGINAL: Login/Logout functions
  const login = async (email: string, password: string): Promise<void> => {
    setLoading(true);
    try {
      const supabaseClient = await getSupabaseClient();
      const { error } = await supabaseClient.auth.signInWithPassword({ email, password });
      if (error) throw error;
      console.log('✅ AuthContext: Login realizado com sucesso');
    } catch (error) {
      console.error('❌ AuthContext: Erro no login:', error);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  const logout = async (): Promise<void> => {
    setLoading(true);
    try {
      const supabaseClient = await getSupabaseClient();
      const { error } = await supabaseClient.auth.signOut(); // ✅ ORIGINAL: signOut
      if (error) throw error;
      
      console.log('✅ AuthContext: Logout realizado com sucesso');
      
      setUser(null);
      setSession(null);
      setUserPlan('free');
      lastSessionTokenRef.current = null;
      
    } catch (error) {
      console.error('❌ AuthContext: Erro no logout:', error);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  // ✅ ENTERPRISE: Enhanced permissions
  const canPerformAction = (action: string): boolean => {
    if (!user) return false;
    
    const planPermissions = {
      free: ['basic_actions'],
      trial: ['basic_actions', 'trial_actions'],
      basic: ['basic_actions', 'paid_actions'],
      pro: ['basic_actions', 'paid_actions', 'pro_actions'],
      enterprise: ['basic_actions', 'paid_actions', 'pro_actions', 'enterprise_actions']
    };
    
    const userPermissions = planPermissions[userPlan as keyof typeof planPermissions] || ['basic_actions'];
    return userPermissions.includes(action);
  };

  // ✅ ENTERPRISE: Memoized value
  const value = React.useMemo(() => ({
    user,
    session,
    loading,
    isReady,
    isAuthenticated: !!user,
    userPlan,
    canPerformAction,
    login,
    logout,
  }), [user, session, loading, isReady, userPlan]);

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth deve ser usado dentro de AuthProvider');
  }
  return context;
};
