// src/index.tsx - ENTERPRISE APPLICATION BOOTSTRAP
import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

// === PERFORMANCE MONITORING ===
interface PerformanceMetrics {
  loadTime: number;
  renderTime: number;
  memoryUsage?: number;
  connectionType?: string;
}

// === ENVIRONMENT SETUP ===
const isProduction = process.env.NODE_ENV === 'production';
const isDevelopment = process.env.NODE_ENV === 'development';

console.log(`🚀 Flux Revenue Dashboard starting...`);
console.log(`📦 Environment: ${process.env.NODE_ENV}`);
console.log(`⚡ React Version: ${React.version}`);

// === PERFORMANCE MEASUREMENT ===
const startTime = performance.now();
let renderStartTime: number;

// === ERROR TRACKING SETUP ===
const setupErrorTracking = () => {
  // Global error handler
  window.addEventListener('error', (event) => {
    console.error('🚨 Global Error:', {
      message: event.message,
      filename: event.filename,
      lineno: event.lineno,
      colno: event.colno,
      error: event.error
    });

    // Send to monitoring service in production
    if (isProduction && window.Sentry) {
      window.Sentry.captureException(event.error);
    }
  });

  // Promise rejection handler
  window.addEventListener('unhandledrejection', (event) => {
    console.error('🚨 Unhandled Promise Rejection:', event.reason);

    if (isProduction && window.Sentry) {
      window.Sentry.captureException(event.reason);
    }
  });

  console.log('✅ Error tracking initialized');
};

// === PERFORMANCE ANALYTICS ===
const setupPerformanceMonitoring = () => {
  // Core Web Vitals
  const observeWebVitals = () => {
    try {
      // FCP - First Contentful Paint
      new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry) => {
          console.log(`📊 FCP: ${entry.startTime.toFixed(2)}ms`);
        });
      }).observe({ entryTypes: ['paint'] });

      // LCP - Largest Contentful Paint
      new PerformanceObserver((list) => {
        const entries = list.getEntries();
        const lastEntry = entries[entries.length - 1];
        console.log(`📊 LCP: ${lastEntry.startTime.toFixed(2)}ms`);
      }).observe({ entryTypes: ['largest-contentful-paint'] });

      // CLS - Cumulative Layout Shift
      new PerformanceObserver((list) => {
        const entries = list.getEntries();
        entries.forEach((entry: any) => {
          if (!entry.hadRecentInput) {
            console.log(`📊 CLS: ${entry.value.toFixed(4)}`);
          }
        });
      }).observe({ entryTypes: ['layout-shift'] });

    } catch (error) {
      console.warn('⚠️ Performance monitoring not fully supported:', error);
    }
  };

  // Connection quality
  const logConnectionInfo = () => {
    if ('connection' in navigator) {
      const connection = (navigator as any).connection;
      console.log(`🌐 Connection: ${connection.effectiveType}, Downlink: ${connection.downlink}Mbps`);
    }
  };

  observeWebVitals();
  logConnectionInfo();

  console.log('✅ Performance monitoring initialized');
};

// === FEATURE DETECTION ===
const checkBrowserFeatures = () => {
  const features = {
    webgl: !!document.createElement('canvas').getContext('webgl'),
    webgl2: !!document.createElement('canvas').getContext('webgl2'),
    serviceWorker: 'serviceWorker' in navigator,
    pushNotifications: 'PushManager' in window,
    webAssembly: typeof WebAssembly === 'object',
    intersectionObserver: 'IntersectionObserver' in window,
    resizeObserver: 'ResizeObserver' in window,
    geolocation: 'geolocation' in navigator,
    localStorage: (() => {
      try {
        const test = '__storage_test__';
        localStorage.setItem(test, test);
        localStorage.removeItem(test);
        return true;
      } catch {
        return false;
      }
    })(),
    sessionStorage: (() => {
      try {
        const test = '__storage_test__';
        sessionStorage.setItem(test, test);
        sessionStorage.removeItem(test);
        return true;
      } catch {
        return false;
      }
    })(),
    indexedDB: 'indexedDB' in window,
    fetch: 'fetch' in window,
    promises: 'Promise' in window,
    asyncAwait: (() => {
      try {
        return (async () => {})().constructor === Promise;
      } catch {
        return false;
      }
    })()
  };

  console.log('🔍 Browser Features:', features);

  // Check for critical missing features
  const criticalFeatures = ['fetch', 'promises', 'localStorage'];
  const missingCritical = criticalFeatures.filter(feature => !features[feature as keyof typeof features]);
  
  if (missingCritical.length > 0) {
    console.error('❌ Missing critical features:', missingCritical);
    // Show fallback UI for unsupported browsers
    return false;
  }

  return true;
};

// === SERVICE WORKER SETUP ===
const setupServiceWorker = async () => {
  if ('serviceWorker' in navigator && isProduction) {
    try {
      const registration = await navigator.serviceWorker.register('/sw.js');
      console.log('✅ Service Worker registered:', registration.scope);
      
      // Handle updates
      registration.addEventListener('updatefound', () => {
        const newWorker = registration.installing;
        if (newWorker) {
          newWorker.addEventListener('statechange', () => {
            if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
              console.log('🔄 New content available, refresh required');
              // Show update notification to user
              if (window.showUpdateNotification) {
                window.showUpdateNotification();
              }
            }
          });
        }
      });

    } catch (error) {
      console.warn('⚠️ Service Worker registration failed:', error);
    }
  }
};

// === FONT PRELOADING ===
const preloadFonts = () => {
  const fontUrls = [
    'https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap'
  ];

  fontUrls.forEach(url => {
    const link = document.createElement('link');
    link.rel = 'preload';
    link.as = 'style';
    link.href = url;
    link.onload = () => {
      link.rel = 'stylesheet';
    };
    document.head.appendChild(link);
  });

  console.log('✅ Fonts preloaded');
};

// === MAIN INITIALIZATION ===
const initializeApp = async () => {
  try {
    console.log('🔧 Initializing Flux Revenue Dashboard...');

    // 1. Setup error tracking first
    setupErrorTracking();

    // 2. Check browser compatibility
    const isSupported = checkBrowserFeatures();
    if (!isSupported) {
      throw new Error('Browser not supported');
    }

    // 3. Setup performance monitoring
    setupPerformanceMonitoring();

    // 4. Preload critical resources
    preloadFonts();

    // 5. Setup service worker
    await setupServiceWorker();

    // 6. Verify root element
    const rootElement = document.getElementById('root');
    if (!rootElement) {
      throw new Error('Root element not found');
    }

    console.log('✅ Root element found:', rootElement.tagName);

    // 7. Create React root
    const root = ReactDOM.createRoot(rootElement);
    console.log('✅ React root created');

    // 8. Measure render time
    renderStartTime = performance.now();

    // 9. Render application with error boundary
    console.log('🎨 Rendering Flux Revenue App...');
    
    root.render(
      <React.StrictMode>
        <App />
      </React.StrictMode>
    );

    // 10. Log performance metrics
    const renderTime = performance.now() - renderStartTime;
    const totalLoadTime = performance.now() - startTime;

    const metrics: PerformanceMetrics = {
      loadTime: totalLoadTime,
      renderTime: renderTime,
      memoryUsage: (performance as any).memory?.usedJSHeapSize,
      connectionType: (navigator as any).connection?.effectiveType
    };

    console.log('📊 Performance Metrics:', {
      ...metrics,
      loadTime: `${metrics.loadTime.toFixed(2)}ms`,
      renderTime: `${metrics.renderTime.toFixed(2)}ms`,
      memoryUsage: metrics.memoryUsage ? `${(metrics.memoryUsage / 1024 / 1024).toFixed(2)}MB` : 'unknown'
    });

    // 11. Send metrics to analytics (production only)
    if (isProduction && window.gtag) {
      window.gtag('event', 'app_loaded', {
        custom_parameter_load_time: Math.round(totalLoadTime),
        custom_parameter_render_time: Math.round(renderTime)
      });
    }

    console.log('🎉 Flux Revenue Dashboard initialized successfully!');

    // 12. Setup development helpers
    if (isDevelopment) {
      // Add helpful global functions for debugging
      (window as any).FluxDebug = {
        metrics,
        React,
        ReactDOM,
        clearStorage: () => {
          localStorage.clear();
          sessionStorage.clear();
          console.log('🧹 Storage cleared');
        },
        reloadApp: () => {
          window.location.reload();
        }
      };
      
      console.log('🛠️ Development helpers available at window.FluxDebug');
    }

  } catch (error) {
    console.error('💥 Failed to initialize app:', error);
    
    // Show fallback error UI
    const rootElement = document.getElementById('root');
    if (rootElement) {
      rootElement.innerHTML = `
        <div style="
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          background: linear-gradient(135deg, #F2F2F7 0%, #E5E5EA 100%);
          font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', sans-serif;
          padding: 24px;
        ">
          <div style="
            background: rgba(255, 255, 255, 0.95);
            backdrop-filter: blur(20px);
            border: 1px solid rgba(255, 59, 48, 0.2);
            border-radius: 24px;
            padding: 48px;
            text-align: center;
            max-width: 480px;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.12);
          ">
            <div style="
              width: 80px;
              height: 80px;
              background: linear-gradient(135deg, #FF3B30 0%, #FF453A 100%);
              border-radius: 20px;
              display: flex;
              align-items: center;
              justify-content: center;
              margin: 0 auto 24px;
              font-size: 36px;
              color: white;
            ">⚠️</div>
            <h2 style="
              font-size: 28px;
              font-weight: 700;
              color: #1D1D1F;
              margin: 0 0 12px 0;
            ">Erro de Inicialização</h2>
            <p style="
              font-size: 17px;
              color: #6D6D70;
              margin: 0 0 24px 0;
              line-height: 1.5;
            ">
              Não foi possível carregar o Flux Revenue Dashboard.
              Tente recarregar a página ou entre em contato com o suporte.
            </p>
            <button onclick="window.location.reload()" style="
              background: linear-gradient(135deg, #007AFF 0%, #0A84FF 100%);
              color: white;
              border: none;
              border-radius: 12px;
              padding: 16px 32px;
              font-size: 17px;
              font-weight: 600;
              cursor: pointer;
              box-shadow: 0 4px 16px rgba(0, 122, 255, 0.24);
            ">
              🔄 Recarregar
            </button>
          </div>
        </div>
      `;
    }

    // Send error to monitoring
    if (isProduction && window.Sentry) {
      window.Sentry.captureException(error);
    }
  }
};

// === TYPE DECLARATIONS ===
declare global {
  interface Window {
    FluxDebug?: any;
    Sentry?: any;
    gtag?: any;
    showUpdateNotification?: () => void;
  }
}

// === START APPLICATION ===
// Use requestIdleCallback for better performance if available
if ('requestIdleCallback' in window) {
  requestIdleCallback(initializeApp);
} else {
  // Fallback for browsers without requestIdleCallback
  setTimeout(initializeApp, 0);
}
