// src/lib/supabaseClient.ts - VERSÃO ENTERPRISE SEM ERROS DE SINTAXE
import { createBrowserClient } from '@supabase/ssr';
import type { Session, AuthError, SupabaseClient } from '@supabase/supabase-js';

// ✅ Configurações avançadas
interface FluxSupabaseConfig {
  retryAttempts: number;
  retryDelay: number;
  cookieDomain: string;
  debug: boolean;
  environment: 'development' | 'production';
}

// ✅ Configuração baseada no ambiente
const config: FluxSupabaseConfig = {
  retryAttempts: 3,
  retryDelay: 1000,
  cookieDomain: process.env.NODE_ENV === 'production' ? '.fluxrevenue.com.br' : 'localhost',
  debug: process.env.NODE_ENV === 'development',
  environment: (process.env.NODE_ENV as 'development' | 'production') || 'development'
};

// ✅ Validação robusta de variáveis
const supabaseUrl = process.env.REACT_APP_SUPABASE_URL;
const supabaseAnonKey = process.env.REACT_APP_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  const missingVars = [
    !supabaseUrl && 'REACT_APP_SUPABASE_URL',
    !supabaseAnonKey && 'REACT_APP_SUPABASE_ANON_KEY'
  ].filter(Boolean);
  
  throw new Error(`Missing Supabase environment variables: ${missingVars.join(', ')}`);
}

// ✅ Função para detectar capacidades do navegador
const getBrowserCapabilities = () => {
  if (typeof window === 'undefined') {
    return { cookies: false, localStorage: false, thirdPartyCookies: false };
  }
  
  return {
    cookies: navigator.cookieEnabled,
    localStorage: (() => {
      try {
        const test = '__storage_test__';
        localStorage.setItem(test, 'test');
        localStorage.removeItem(test);
        return true;
      } catch {
        return false;
      }
    })(),
    thirdPartyCookies: document.cookie.indexOf('SameSite=None') !== -1
  };
};

// ✅ Configuração otimizada de cookies
const getCookieConfig = () => {
  const capabilities = getBrowserCapabilities();
  const isProduction = config.environment === 'production';
  
  if (isProduction && capabilities.thirdPartyCookies) {
    return {
      domain: config.cookieDomain,
      path: '/',
      sameSite: 'none' as const,
      secure: true,
      maxAge: 60 * 60 * 24 * 30,
      httpOnly: false
    };
  } else {
    return {
      domain: config.cookieDomain,
      path: '/',
      sameSite: 'lax' as const,
      secure: isProduction,
      maxAge: 60 * 60 * 24 * 7,
      httpOnly: false
    };
  }
};

// ✅ Storage customizado
const createCustomStorage = () => {
  return {
    getItem: (key: string) => {
      if (typeof window === 'undefined') return null;
      
      try {
        const item = localStorage.getItem(key);
        if (item) return item;
      } catch (e) {
        console.warn('LocalStorage not available, using cookies');
      }
      
      const cookies = document.cookie.split(';');
      const cookie = cookies.find(c => c.trim().startsWith(`${key}=`));
      return cookie ? cookie.split('=')[1] : null;
    },
    
    setItem: (key: string, value: string) => {
      if (typeof window === 'undefined') return;
      
      try {
        localStorage.setItem(key, value);
      } catch (e) {
        console.warn('LocalStorage not available, using cookies');
      }
      
      const cookieConfig = getCookieConfig();
      const cookieString = [
        `${key}=${value}`,
        `Domain=${cookieConfig.domain}`,
        `Path=${cookieConfig.path}`,
        `Max-Age=${cookieConfig.maxAge}`,
        `SameSite=${cookieConfig.sameSite}`,
        cookieConfig.secure ? 'Secure' : ''
      ].filter(Boolean).join('; ');
      
      document.cookie = cookieString;
    },
    
    removeItem: (key: string) => {
      if (typeof window === 'undefined') return;
      
      try {
        localStorage.removeItem(key);
      } catch (e) {
        console.warn('LocalStorage not available');
      }
      
      const cookieConfig = getCookieConfig();
      document.cookie = `${key}=; Domain=${cookieConfig.domain}; Path=${cookieConfig.path}; Max-Age=0`;
    }
  };
};

// ✅ Função para inicializar cliente com retry
const initializeSupabaseClient = async (attempt: number = 1): Promise<SupabaseClient> => {
  try {
    const cookieConfig = getCookieConfig();
    
    if (config.debug) {
      console.log(`🔧 Flux Revenue - Initializing Supabase (attempt ${attempt})`, {
        url: supabaseUrl,
        environment: config.environment,
        cookieConfig,
        capabilities: getBrowserCapabilities()
      });
    }
    
    const client = createBrowserClient(supabaseUrl, supabaseAnonKey, {
      auth: {
        persistSession: true,
        detectSessionInUrl: true,
        storageKey: `sb-flux-${config.environment}`,
        autoRefreshToken: true,
        flowType: 'pkce',
        debug: config.debug,
        storage: createCustomStorage()
      },
      global: {
        headers: {
          'X-Client-Info': 'flux-revenue-dashboard',
          'X-Client-Version': '2.0.0',
          'X-Environment': config.environment
        }
      },
      realtime: {
        params: {
          eventsPerSecond: 10
        }
      }
    });
    
    // ✅ Teste de conexão com retry
    const { data, error } = await client.auth.getSession();
    
    if (error && attempt < config.retryAttempts) {
      console.warn(`⚠️ Supabase connection failed (attempt ${attempt}), retrying...`, error.message);
      await new Promise(resolve => setTimeout(resolve, config.retryDelay * attempt));
      return initializeSupabaseClient(attempt + 1);
    }
    
    if (config.debug) {
      console.log('✅ Supabase initialized successfully', {
        hasSession: !!data.session,
        user: data.session?.user?.email || 'No user',
        attempt
      });
    }
    
    return client;
    
  } catch (error) {
    if (attempt < config.retryAttempts) {
      console.warn(`❌ Supabase initialization failed (attempt ${attempt}), retrying...`, error);
      await new Promise(resolve => setTimeout(resolve, config.retryDelay * attempt));
      return initializeSupabaseClient(attempt + 1);
    }
    
    console.error('❌ Supabase initialization failed after all retries:', error);
    throw error;
  }
};

// ✅ Singleton pattern
let supabaseInstance: SupabaseClient | null = null;
let initializationPromise: Promise<SupabaseClient> | null = null;

// ✅ Função para obter instância Supabase
export const getSupabaseClient = (): Promise<SupabaseClient> => {
  if (supabaseInstance) {
    return Promise.resolve(supabaseInstance);
  }
  
  if (initializationPromise) {
    return initializationPromise;
  }
  
  if (typeof window !== 'undefined' && (window as any).fluxSupabase) {
    const globalInstance = (window as any).fluxSupabase;
    if (globalInstance && typeof globalInstance.auth === 'object') {
      supabaseInstance = globalInstance;
      return Promise.resolve(globalInstance);
    }
  }
  
  initializationPromise = initializeSupabaseClient().then(client => {
    supabaseInstance = client;
    
    if (typeof window !== 'undefined') {
      (window as any).fluxSupabase = client;
    }
    
    initializationPromise = null;
    return client;
  }).catch(error => {
    initializationPromise = null;
    throw error;
  });
  
  return initializationPromise;
};

// ✅ Instância síncrona para compatibilidade
const createSyncInstance = (): SupabaseClient => {
  if (typeof window !== 'undefined' && (window as any).fluxSupabase) {
    const globalInstance = (window as any).fluxSupabase;
    if (globalInstance && typeof globalInstance.auth === 'object') {
      return globalInstance;
    }
  }
  
  const client = createBrowserClient(supabaseUrl, supabaseAnonKey, {
    auth: {
      persistSession: true,
      detectSessionInUrl: true,
      storageKey: `sb-flux-${config.environment}`,
      autoRefreshToken: true,
      flowType: 'pkce'
    },
    global: {
      headers: {
        'X-Client-Info': 'flux-revenue-dashboard',
        'X-Client-Version': '2.0.0',
        'X-Environment': config.environment
      }
    }
  });
  
  if (typeof window !== 'undefined') {
    (window as any).fluxSupabase = client;
  }
  
  return client;
};

// ✅ Export principal (sintaxe correta)
export const supabase = createSyncInstance();

// ✅ Utilitários para debugging
export const supabaseUtils = {
  async checkConnection(): Promise<{ connected: boolean; user?: string; error?: string }> {
    try {
      const client = await getSupabaseClient();
      const { data, error } = await client.auth.getSession();
      
      return {
        connected: !error,
        user: data.session?.user?.email,
        error: error?.message
      };
    } catch (error) {
      return {
        connected: false,
        error: (error as Error).message
      };
    }
  },
  
  async reset(): Promise<void> {
    supabaseInstance = null;
    initializationPromise = null;
    
    if (typeof window !== 'undefined') {
      delete (window as any).fluxSupabase;
    }
    
    await getSupabaseClient();
  },
  
  getCookieStats() {
    if (typeof window === 'undefined') {
      return { cookies: [], total: 0, capabilities: getBrowserCapabilities() };
    }
    
    const cookies = document.cookie.split(';').map(c => c.trim());
    const fluxCookies = cookies.filter(c => c.startsWith('sb-flux'));
    
    return {
      cookies: fluxCookies,
      total: fluxCookies.length,
      capabilities: getBrowserCapabilities()
    };
  },
  
  async ensureInitialized(): Promise<SupabaseClient> {
    return await getSupabaseClient();
  }
};

// ✅ Type declarations
declare global {
  interface Window {
    fluxSupabase?: SupabaseClient;
  }
}

// ✅ Export default
export default supabase;
